proof fn phi_1_tla_forall_always_equality_variant_intensional_bridge(a_to_always: spec_fn(int) -> TempPred<int>, a_to_p: spec_fn(int) -> TempPred<int>)
    requires
        forall |a: int| #![trigger a_to_always(a)] a_to_always(a).entails((|a: int| always(a_to_p(a)))(a)) && ((|a: int| always(a_to_p(a)))(a)).entails(a_to_always(a)),
    ensures
        tla_forall(a_to_always) == always(tla_forall(a_to_p)),
{
    tla_forall_always_equality_variant::<int, int>(a_to_always, a_to_p);
}

